import 'package:flutter/material.dart'; import '../../domain/entities/report.dart'; import '../utils/report_reason_localization.dart'; class ReportReasonTile extends StatelessWidget{final ReportReason reason; final bool selected; final VoidCallback onTap; const ReportReasonTile({super.key,required this.reason,required this.selected,required this.onTap}); @override Widget build(BuildContext context)=>Card(child:RadioListTile<ReportReason>(value:reason,groupValue:selected?reason:null,onChanged:(_)=>onTap(),title:Text(reason.title),subtitle:Text(reason.description)));}
